// Problem catalogue.  In production these would come from Postgres
// (see database/schema.sql); for the demo we keep them as a static
// in-memory list so the platform is runnable without a database.
//
// NOTE: `starter` holds a STUB (input scaffold + TODO), never the answer.
// The worked solution lives in `solution` and is shown only in the locked
// "Solution" tab.  All `test_cases[].expected` values were produced by
// running the reference solution under Python, so the judge returns AC
// for `solution` on every problem.  (Generated by tooling/cs_gen.py.)

export type CheckerType = "exact" | "trimmed" | "numeric_eps" | "custom_checker";
export type Difficulty = "Easy" | "Medium" | "Hard";
export type LanguageCode = "python3" | "cpp17" | "java17" | "node18" | "go121";

export interface TestCase {
  seq: number;
  input: string;
  expected: string;
  is_sample: boolean;
  label?: string;
}

export interface Example {
  input: string;
  output: string;
  explanation?: string;
}

export interface Complexity {
  time: string;
  space: string;
}

export interface Problem {
  slug: string;
  problem_id: number;
  title: string;
  difficulty: Difficulty;
  tags: string[];
  description: string;
  constraints: string[];
  examples: Example[];
  hints: string[];
  editorial: string;
  approach: string;                       // markdown, shown in Solution tab
  complexity: Complexity;
  company_tags: string[];
  frequency: number;                      // 0-100, "how often asked"
  related: string[];                      // related problem slugs
  time_limit_ms: number;
  memory_limit_mb: number;
  checker_type: CheckerType;
  checker_eps?: number;
  starter: Partial<Record<LanguageCode, string>>;   // STUB, never the answer
  solution: Partial<Record<LanguageCode, string>>;  // reference solution
  test_cases: TestCase[];
  acceptance_rate: number;
  likes: number;
  dislikes: number;
}

export interface ProblemList {
  slug: string;
  name: string;
  description: string;
  icon: string;
  problem_slugs: string[];
}

