export function findProblem(slug: string): Problem | undefined {
  return PROBLEMS.find((p) => p.slug === slug);
}

export function findList(slug: string): ProblemList | undefined {
  return PROBLEM_LISTS.find((l) => l.slug === slug);
}

export function listTags(): string[] {
  const s = new Set<string>();
  PROBLEMS.forEach((p) => p.tags.forEach((t) => s.add(t)));
  return Array.from(s).sort();
}

export function listCompanies(): string[] {
  const s = new Set<string>();
  PROBLEMS.forEach((p) => p.company_tags.forEach((c) => s.add(c)));
  return Array.from(s).sort();
}

export function relatedProblems(slug: string): Problem[] {
  const p = findProblem(slug);
  if (!p) return [];
  return p.related.map(findProblem).filter((x): x is Problem => Boolean(x));
}

// Deterministic "daily" pick — same problem all day, rotates by date.
export function dailyProblem(date = new Date()): Problem {
  const dayOfYear = Math.floor(
    (date.getTime() - new Date(date.getFullYear(), 0, 0).getTime()) /
      (1000 * 60 * 60 * 24),
  );
  return PROBLEMS[dayOfYear % PROBLEMS.length];
}

// Random problem, optionally excluding one slug (for a "pick another").
export function randomProblem(excludeSlug?: string): Problem {
  const pool = excludeSlug ? PROBLEMS.filter((p) => p.slug !== excludeSlug) : PROBLEMS;
  const idx = Math.floor(Math.random() * pool.length);
  return pool[idx] ?? PROBLEMS[0];
}
